        <div id="quote-status" style="color:#666;">Loading…</div>
        <div id="quote-list" style="display:grid; gap:8px;"></div>
      </div>
    `

    const status = parent.querySelector("#quote-status")
    const list = parent.querySelector("#quote-list")

    try {
      const data = await fetch("https://api.example.test/quotes/v2").then(r => r.json())
      const items = Array.isArray(data) ? data : (data.quotes || data.items || [])

      if (!items.length) {
        status.textContent = "No quotes available"
        return
      }

      status.textContent = ""
      list.innerHTML = items.map(q => {
        const symbol = q.symbol ?? q.ticker ?? "—"
        const price = q.price ?? q.last ?? q.value ?? "—"
        const change = q.change ?? q.delta ?? null
        const changeText = change === null ? "" : ` <span style="color:${change >= 0 ? "#0a7" : "#c33"}">${change >= 0 ? "▲" : "▼"} ${change}</span>`
        return `<div style="display:flex; justify-content:space-between; padding:10px 12px; border:1px solid #ddd; border-radius:10px; background:#fff;">
          <span>${symbol}</span>
          <span>${price}${changeText}</span>
        </div>`
      }).join("")
    } catch (err) {
      status.textContent = "Failed to load quotes"
      list.innerHTML = `<div style="color:#c33;">${String(err.message || err)}</div>`
    }
  }
})

