return await space.current.patchWidget("snake-game", {
  edits: [
    {
      path: "renderer",
      replace: `(parent) => {
  const cols = 20
  const rows = 20
  const cellSize = 24
  const boardW = cols * cellSize
  const boardH = rows * cellSize

  parent.innerHTML = \`
    <style>
      .wrap { display: flex; flex-direction: column; gap: 10px; align-items: center; font-family: system-ui, sans-serif; }
      canvas { background: #111; border: 2px solid #333; border-radius: 10px; image-rendering: auto; box-shadow: 0 8px 24px rgba(0,0,0,.25); }
      .hud { color: #eee; font-size: 14px; display:flex; gap:12px; align-items:center; }
      .hint { color: #999; font-size: 12px; }
    </style>
    <div class="wrap">
      <div class="hud"><span id="score">Score: 0</span><span id="status"></span></div>
      <canvas id="game" width="\${boardW}" height="\${boardH}"></canvas>
      <div class="hint">Use arrow keys. Smooth movement is animated between squares.</div>
    </div>
  \`

  const canvas = parent.querySelector("#game")
  const ctx = canvas.getContext("2d")
  const scoreEl = parent.querySelector("#score")
  const statusEl = parent.querySelector("#status")

  let snake = [{ x: 10, y: 10 }]
  let prevSnake = snake.map(p => ({ ...p }))
  let dir = { x: 1, y: 0 }
  let nextDir = { x: 1, y: 0 }
  let food = spawnFood()
  let score = 0
  let alive = true
  let lastStep = performance.now()
  const stepMs = 140

  function spawnFood() {
    while (true) {
      const p = {
        x: Math.floor(Math.random() * cols),
        y: Math.floor(Math.random() * rows)
      }
      if (!snake.some(s => s.x === p.x && s.y === p.y)) return p
    }
  }

  function clampDir(a, b) {
    return !(a.x === -b.x && a.y === -b.y)
  }

  window.addEventListener("keydown", onKey)
  function onKey(e) {
    const map = {
      ArrowUp: { x: 0, y: -1 },
      ArrowDown: { x: 0, y: 1 },
      ArrowLeft: { x: -1, y: 0 },
      ArrowRight: { x: 1, y: 0 },
    }
    const nd = map[e.key]
    if (!nd) return
    if (clampDir(nd, dir)) nextDir = nd
  }

  function step() {
    if (!alive) return
    prevSnake = snake.map(p => ({ ...p }))
    dir = nextDir
    const head = snake[0]
    const newHead = { x: head.x + dir.x, y: head.y + dir.y }

    if (newHead.x < 0 || newHead.x >= cols || newHead.y < 0 || newHead.y >= rows || snake.some((s, i) => i && s.x === newHead.x && s.y === newHead.y)) {
      alive = false
      statusEl.textContent = "Game over"
      return
    }

    snake.unshift(newHead)

    if (newHead.x === food.x && newHead.y === food.y) {
      score++
      scoreEl.textContent = "Score: " + score
      food = spawnFood()
    } else {
      snake.pop()
    }
  }

  function lerp(a, b, t) {
    return a + (b - a) * t
  }

  function drawSegment(x, y, isHead, alpha = 1) {
    const pad = 2
    ctx.save()
    ctx.globalAlpha = alpha
    ctx.fillStyle = isHead ? "#5ee06a" : "#2fb344"
    ctx.beginPath()
    ctx.roundRect(x + pad, y + pad, cellSize - pad * 2, cellSize - pad * 2, 6)
    ctx.fill()
    ctx.restore()
  }

  function render(now) {
    const elapsed = now - lastStep
    if (elapsed >= stepMs) {
      lastStep = now
      step()
    }
    const t = Math.min(1, (now - lastStep) / stepMs)

    ctx.clearRect(0, 0, boardW, boardH)

    for (let y = 0; y < rows; y++) {
      for (let x = 0; x < cols; x++) {
        ctx.fillStyle = (x + y) % 2 ? "#171717" : "#131313"
        ctx.fillRect(x * cellSize, y * cellSize, cellSize, cellSize)
      }
    }

    ctx.fillStyle = "#ff5d5d"
    ctx.beginPath()
    ctx.arc(food.x * cellSize + cellSize / 2, food.y * cellSize + cellSize / 2, cellSize * 0.28, 0, Math.PI * 2)
    ctx.fill()

    for (let i = snake.length - 1; i >= 0; i--) {
      const curr = snake[i]
      const prev = prevSnake[i] || curr
      const x = lerp(prev.x, curr.x, t) * cellSize
      const y = lerp(prev.y, curr.y, t) * cellSize
      drawSegment(x, y, i === 0, 1)
    }

    if (alive) requestAnimationFrame(render)
  }

  requestAnimationFrame(render)
}`
    }
  ]
})

