return await space.current.patchWidget("snake-game", {
  edits: [
    {
      op: "replace",
      path: "/renderer",
      value: async (parent) => {
        parent.innerHTML = `
          <style>
            .wrap { display:flex; flex-direction:column; gap:12px; align-items:center; font-family:sans-serif; }
            .board {
              position: relative;
              width: 320px;
              height: 320px;
              background: #0f172a;
              border: 2px solid #334155;
              border-radius: 14px;
              overflow: hidden;
              box-shadow: 0 10px 30px rgba(0,0,0,.25);
            }
            .cell {
              position: absolute;
              width: 20px;
              height: 20px;
              border-radius: 6px;
              background: #22c55e;
              box-shadow: 0 0 0 1px rgba(255,255,255,.08) inset;
              transition: transform 120ms linear, opacity 120ms linear;
              will-change: transform;
            }
            .head { background: #86efac; }
            .food { background: #ef4444; border-radius: 50%; }
            .hud { color: #cbd5e1; display:flex; gap:16px; align-items:center; }
            button { padding:8px 12px; border-radius:10px; border:0; background:#2563eb; color:white; }
          </style>
          <div class="wrap">
            <div class="hud"><div id="score">Score: 0</div><button id="restart">Restart</button></div>
            <div class="board" id="board"></div>
            <div style="color:#94a3b8;font-size:12px">Use arrow keys</div>
          </div>
        `

        const board = parent.querySelector("#board")
        const scoreEl = parent.querySelector("#score")
        const restart = parent.querySelector("#restart")
        const size = 16
        const cellSize = 20
        const speed = 120

        let snake, dir, nextDir, food, score, alive, tickTimer, animTimer, prevSnake, prevFood

        const randCell = () => ({
          x: Math.floor(Math.random() * size),
          y: Math.floor(Math.random() * size),
        })

        const same = (a, b) => a.x === b.x && a.y === b.y

        function init() {
          snake = [{ x: 8, y: 8 }, { x: 7, y: 8 }, { x: 6, y: 8 }]
          dir = { x: 1, y: 0 }
          nextDir = dir
          food = randCell()
          while (snake.some(s => same(s, food))) food = randCell()
          score = 0
          alive = true
          prevSnake = snake.map(p => ({ ...p }))
          prevFood = { ...food }
          scoreEl.textContent = `Score: ${score}`
          render(0)
          clearInterval(tickTimer)
          clearInterval(animTimer)
          tickTimer = setInterval(step, speed)
          let t0 = performance.now()
          animTimer = setInterval(() => {
            const t = Math.min(1, (performance.now() - t0) / speed)
            render(t)
            if (t >= 1) t0 = performance.now()
          }, 16)
        }

        function step() {
          if (!alive) return
          if (!(nextDir.x === -dir.x && nextDir.y === -dir.y)) dir = nextDir
          prevSnake = snake.map(p => ({ ...p }))
          prevFood = { ...food }

          const head = { x: (snake[0].x + dir.x + size) % size, y: (snake[0].y + dir.y + size) % size }
          snake.unshift(head)

          if (same(head, food)) {
            score++
            scoreEl.textContent = `Score: ${score}`
            food = randCell()
            while (snake.some(s => same(s, food))) food = randCell()
          } else {
            snake.pop()
          }

          if (snake.slice(1).some(s => same(s, head))) {
            alive = false
            clearInterval(tickTimer)
          }
        }

        function drawCell(el, x, y, t) {
          el.style.transform = `translate(${x * cellSize}px, ${y * cellSize}px) translate(${t}px, ${t}px)`
        }

        function render(t) {
          board.innerHTML = ""
          const lerp = (a, b) => a + (b - a) * t

          snake.forEach((seg, i) => {
            const prev = prevSnake[i] || prevSnake[prevSnake.length - 1] || seg
            const x = lerp(prev.x, seg.x)
            const y = lerp(prev.y, seg.y)
            const el = document.createElement("div")
            el.className = `cell ${i === 0 ? "head" : ""}`
            el.style.width = `${cellSize - 2}px`
            el.style.height = `${cellSize - 2}px`
            drawCell(el, x, y, 1)
            board.appendChild(el)
          })

          const foodEl = document.createElement("div")
          foodEl.className = "cell food"
          foodEl.style.width = `${cellSize - 6}px`
          foodEl.style.height = `${cellSize - 6}px`
          const fx = lerp(prevFood.x, food.x)
          const fy = lerp(prevFood.y, food.y)
          drawCell(foodEl, fx + 0.15, fy + 0.15, 0)
          board.appendChild(foodEl)
        }

        window.addEventListener("keydown", e => {
          const map = {
            ArrowUp: { x: 0, y: -1 },
            ArrowDown: { x: 0, y: 1 },
            ArrowLeft: { x: -1, y: 0 },
            ArrowRight: { x: 1, y: 0 },
          }
          if (map[e.key]) nextDir = map[e.key]
        })

        restart.onclick = init
        init()
      }
    }
  ]
})
